(
    (-20.6 0 -0.5)    // 0
    (0 0 -0.5)        // 1
    (0 25.4 -0.5)     // 2
    (-20.6 25.4 -0.5) // 3
    (-20.6 0 0.5)     // 4
    (0 0 0.5)         // 5
    (0 25.4 0.5)      // 6
    (-20.6 25.4 0.5)  // 7
);

